import React, { useState, useCallback, useEffect, useRef } from 'react';
import FAWTable from '../FAWTable/FAWTable';
import { Box } from '@mui/material';

const WorkQueueTables = ({
  allUsersData = [],
  queueUsersData = [],
  onQueueUsersChange,
  onAllUsersChange,
  searchPlaceholder = 'Search',
  noRowsMessage = 'No users found.',
  noQueueMessage = 'No List',
  height = '400px'
}) => {
  const [allUsers, setAllUsers] = useState(allUsersData || []);
  const [queueUsers, setQueueUsers] = useState(queueUsersData || []);
  const [isLoading, setIsLoading] = useState(true);
  const queueTableApiRef = useRef(null);
  const allUsersTableApiRef = useRef(null);
  const queueTableContainerRef = useRef(null);
  const allUsersTableContainerRef = useRef(null);
  const dragOverTargetRef = useRef(null);
  const isDraggingRef = useRef(false);
  const mouseMoveHandlerRef = useRef(null);

  // Update local state when props change
  useEffect(() => {
    if (allUsersData) {
      setAllUsers(allUsersData);
    }
  }, [allUsersData]);

  useEffect(() => {
    if (queueUsersData) {
      setQueueUsers(queueUsersData);
    }
  }, [queueUsersData]);

  // Set loading to false once component is mounted and data is ready
  useEffect(() => {
    // Small delay to show skeleton loading initially
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 300);
    return () => clearTimeout(timer);
  }, []);

  // Setup HTML5 drag and drop on table rows for cross-table drag
  useEffect(() => {
    const setupRowDragHandlers = () => {
      // Setup drag handlers for All Users table rows
      if (allUsersTableContainerRef.current) {
        const allUsersRows = allUsersTableContainerRef.current.querySelectorAll('.MuiDataGrid-row');
        allUsersRows.forEach((rowElement) => {
          if (!rowElement.dataset.dragSetup) {
            rowElement.dataset.dragSetup = 'true';
            rowElement.setAttribute('draggable', 'true');
            rowElement.style.cursor = 'grab';
            
            const rowId = rowElement.getAttribute('data-id');
            if (rowId) {
              rowElement.addEventListener('dragstart', (e) => {
                const rowData = allUsers.find(u => String(u.Id || u.id) === String(rowId));
                if (rowData) {
                  window._workQueueDraggedUser = rowData;
                  window._workQueueDragSource = 'all-users';
                  isDraggingRef.current = true;
                  e.dataTransfer.effectAllowed = 'move';
                  e.dataTransfer.dropEffect = 'move';
                  e.dataTransfer.setData('text/plain', JSON.stringify(rowData));
                  rowElement.style.cursor = 'grabbing';
                  rowElement.style.opacity = '0.5';
                  
                  // Add global mouse move listener
                  mouseMoveHandlerRef.current = handleGlobalMouseMove;
                  document.addEventListener('mousemove', mouseMoveHandlerRef.current);
                } else {
                  e.preventDefault();
                }
              });
              
              rowElement.addEventListener('dragend', (e) => {
                rowElement.style.cursor = 'grab';
                rowElement.style.opacity = '1';
                
                // Check if dropped on queue table
                const droppedOnQueue = dragOverTargetRef.current === 'queue-users';
                if (droppedOnQueue && window._workQueueDraggedUser) {
                  handleAllUsersDragEnd({ event: e });
                }
                
                // Clean up
                isDraggingRef.current = false;
                if (mouseMoveHandlerRef.current) {
                  document.removeEventListener('mousemove', mouseMoveHandlerRef.current);
                  mouseMoveHandlerRef.current = null;
                }
                if (queueTableContainerRef.current) {
                  queueTableContainerRef.current.style.backgroundColor = 'transparent';
                  queueTableContainerRef.current.style.border = 'none';
                }
                window._workQueueDraggedUser = null;
                window._workQueueDragSource = null;
                dragOverTargetRef.current = null;
              });
            }
          }
        });
      }

      // Setup drag handlers for Queue Users table rows (for dragging back to All Users)
      if (queueTableContainerRef.current) {
        const queueRows = queueTableContainerRef.current.querySelectorAll('.MuiDataGrid-row');
        queueRows.forEach((rowElement) => {
          if (!rowElement.dataset.dragSetup) {
            rowElement.dataset.dragSetup = 'true';
            rowElement.setAttribute('draggable', 'true');
            rowElement.style.cursor = 'grab';
            
            const rowId = rowElement.getAttribute('data-id');
            if (rowId) {
              rowElement.addEventListener('dragstart', (e) => {
                const rowData = queueUsers.find(u => String(u.Id || u.id) === String(rowId));
                if (rowData) {
                  window._workQueueDraggedUser = rowData;
                  window._workQueueDragSource = 'queue-users';
                  isDraggingRef.current = true;
                  e.dataTransfer.effectAllowed = 'move';
                  e.dataTransfer.dropEffect = 'move';
                  e.dataTransfer.setData('text/plain', JSON.stringify(rowData));
                  rowElement.style.cursor = 'grabbing';
                  rowElement.style.opacity = '0.5';
                  
                  // Add global mouse move listener
                  mouseMoveHandlerRef.current = handleGlobalMouseMove;
                  document.addEventListener('mousemove', mouseMoveHandlerRef.current);
                } else {
                  e.preventDefault();
                }
              });
              
              rowElement.addEventListener('dragend', (e) => {
                rowElement.style.cursor = 'grab';
                rowElement.style.opacity = '1';
                
                // Check if dropped on All Users table
                const droppedOnAllUsers = dragOverTargetRef.current === 'all-users';
                if (droppedOnAllUsers && window._workQueueDraggedUser) {
                  handleQueueDragEnd({ event: e });
                }
                
                // Clean up
                isDraggingRef.current = false;
                if (mouseMoveHandlerRef.current) {
                  document.removeEventListener('mousemove', mouseMoveHandlerRef.current);
                  mouseMoveHandlerRef.current = null;
                }
                if (allUsersTableContainerRef.current) {
                  allUsersTableContainerRef.current.style.backgroundColor = 'transparent';
                  allUsersTableContainerRef.current.style.border = 'none';
                }
                window._workQueueDraggedUser = null;
                window._workQueueDragSource = null;
                dragOverTargetRef.current = null;
              });
            }
          }
        });
      }
    };

    // Setup after a delay to ensure tables are rendered
    const timeoutId = setTimeout(setupRowDragHandlers, 200);
    
    // Also setup when data changes
    const intervalId = setInterval(setupRowDragHandlers, 500);

    return () => {
      clearTimeout(timeoutId);
      clearInterval(intervalId);
    };
  }, [allUsers, queueUsers, handleGlobalMouseMove, handleAllUsersDragEnd, handleQueueDragEnd]);

  // Update priorities when queue users change
  const updatePriorities = useCallback((users) => {
    return users.map((user, index) => ({
      ...user,
      Priority: index + 1
    }));
  }, []);

  // Global mouse move handler for cross-table drag detection
  const handleGlobalMouseMove = useCallback((e) => {
    if (!isDraggingRef.current) return;
    
    // Check which table container the mouse is over
    const queueRect = queueTableContainerRef.current?.getBoundingClientRect();
    const allUsersRect = allUsersTableContainerRef.current?.getBoundingClientRect();
    
    const mouseX = e.clientX;
    const mouseY = e.clientY;
    
    // Check if over queue table
    if (queueRect && 
        mouseX >= queueRect.left && mouseX <= queueRect.right && 
        mouseY >= queueRect.top && mouseY <= queueRect.bottom) {
      if (window._workQueueDragSource === 'all-users') {
        dragOverTargetRef.current = 'queue-users';
        if (queueTableContainerRef.current) {
          queueTableContainerRef.current.style.backgroundColor = '#e3f2fd';
          queueTableContainerRef.current.style.border = '2px dashed #1976d2';
        }
        if (allUsersTableContainerRef.current) {
          allUsersTableContainerRef.current.style.backgroundColor = 'transparent';
          allUsersTableContainerRef.current.style.border = 'none';
        }
      }
    }
    // Check if over all users table
    else if (allUsersRect && 
             mouseX >= allUsersRect.left && mouseX <= allUsersRect.right && 
             mouseY >= allUsersRect.top && mouseY <= allUsersRect.bottom) {
      if (window._workQueueDragSource === 'queue-users') {
        dragOverTargetRef.current = 'all-users';
        if (allUsersTableContainerRef.current) {
          allUsersTableContainerRef.current.style.backgroundColor = '#e3f2fd';
          allUsersTableContainerRef.current.style.border = '2px dashed #1976d2';
        }
        if (queueTableContainerRef.current) {
          queueTableContainerRef.current.style.backgroundColor = 'transparent';
          queueTableContainerRef.current.style.border = 'none';
        }
      }
    }
    // Not over any table
    else {
      dragOverTargetRef.current = null;
      if (queueTableContainerRef.current) {
        queueTableContainerRef.current.style.backgroundColor = 'transparent';
        queueTableContainerRef.current.style.border = 'none';
      }
      if (allUsersTableContainerRef.current) {
        allUsersTableContainerRef.current.style.backgroundColor = 'transparent';
        allUsersTableContainerRef.current.style.border = 'none';
      }
    }
  }, []);

  // Handle drag start from All Users table (for cross-grid drag to Queue)
  const handleAllUsersDragStart = useCallback((params) => {
    try {
      // Store the dragged user for potential cross-grid drop
      if (params && params.api && params.node && params.node.data) {
        window._workQueueDraggedUser = params.node.data;
        window._workQueueDragSource = 'all-users';
        isDraggingRef.current = true;
        dragOverTargetRef.current = null;
        
        // Add global mouse move listener for cross-table drag detection
        if (handleGlobalMouseMove) {
          mouseMoveHandlerRef.current = handleGlobalMouseMove;
          document.addEventListener('mousemove', mouseMoveHandlerRef.current);
        }
        
        // Prevent the "not allowed" cursor by allowing the drag
        // Set dataTransfer effectAllowed to allow copy/move
        if (params.event && params.event.dataTransfer) {
          params.event.dataTransfer.effectAllowed = 'move';
          params.event.dataTransfer.dropEffect = 'move';
        }
        
        // Also set up HTML5 drag on the row element if available
        if (params.node && params.node.rowElement) {
          params.node.rowElement.setAttribute('draggable', 'true');
          params.node.rowElement.style.cursor = 'move';
        }
      }
    } catch (error) {
      console.error('Error in handleAllUsersDragStart:', error);
    }
  }, [handleGlobalMouseMove]);

  // Handle drag move from All Users table - use global mouse tracking
  const handleAllUsersDragMove = useCallback((params) => {
    // Global mouse move handler will handle the detection
    // This callback is kept for compatibility but global handler does the work
  }, []);

  // Handle drag end from All Users table
  const handleAllUsersDragEnd = useCallback((params) => {
    // Check if dropped on queue table area
    const droppedOnQueue = dragOverTargetRef.current === 'queue-users';
    
    // Also check final mouse position as fallback
    let finalCheckDroppedOnQueue = false;
    if (queueTableContainerRef.current) {
      const rect = queueTableContainerRef.current.getBoundingClientRect();
      // Use document.elementFromPoint to check what's under the mouse
      const elementUnderMouse = document.elementFromPoint(
        params?.event?.clientX || 0,
        params?.event?.clientY || 0
      );
      if (elementUnderMouse && queueTableContainerRef.current.contains(elementUnderMouse)) {
        finalCheckDroppedOnQueue = true;
      }
    }
    
    const shouldMoveToQueue = droppedOnQueue || finalCheckDroppedOnQueue;
    
    if (window._workQueueDraggedUser && window._workQueueDragSource === 'all-users' && shouldMoveToQueue) {
      const userToAdd = window._workQueueDraggedUser;
      
      // Check if user already exists in queue
      const userExists = queueUsers.some(u => u.Id === userToAdd.Id);
      if (!userExists) {
        // Create new queue user entry
        const nextPriority = queueUsers.length + 1;
        const newQueueUser = {
          ...userToAdd,
          Priority: nextPriority,
          DateAdded: new Date().toLocaleDateString('en-US', { 
            month: '2-digit', 
            day: '2-digit', 
            year: 'numeric' 
          })
        };

        const newQueueUsers = [...queueUsers, newQueueUser];
        const updatedQueueUsers = updatePriorities(newQueueUsers);
        
        // Remove from all users
        const newAllUsers = allUsers.filter(u => u.Id !== userToAdd.Id);
        
        setQueueUsers(updatedQueueUsers);
        setAllUsers(newAllUsers);
        
        if (onQueueUsersChange) {
          onQueueUsersChange(updatedQueueUsers);
        }
        if (onAllUsersChange) {
          onAllUsersChange(newAllUsers);
        }
      }
    }
    
    // Reset drag over styling
    if (queueTableContainerRef.current) {
      queueTableContainerRef.current.style.backgroundColor = 'transparent';
      queueTableContainerRef.current.style.border = 'none';
    }
    if (allUsersTableContainerRef.current) {
      allUsersTableContainerRef.current.style.backgroundColor = 'transparent';
      allUsersTableContainerRef.current.style.border = 'none';
    }
    
    // Clean up
    isDraggingRef.current = false;
    if (mouseMoveHandlerRef.current) {
      document.removeEventListener('mousemove', mouseMoveHandlerRef.current);
      mouseMoveHandlerRef.current = null;
    }
    window._workQueueDraggedUser = null;
    window._workQueueDragSource = null;
    dragOverTargetRef.current = null;
  }, [queueUsers, allUsers, updatePriorities, onQueueUsersChange, onAllUsersChange]);

  // Handle drag start from Queue table (for cross-grid drag to All Users)
  const handleQueueDragStart = useCallback((params) => {
    try {
      // Store the dragged user for potential cross-grid drop
      if (params && params.api && params.node && params.node.data) {
        window._workQueueDraggedUser = params.node.data;
        window._workQueueDragSource = 'queue-users';
        isDraggingRef.current = true;
        dragOverTargetRef.current = null;
        
        // Add global mouse move listener for cross-table drag detection
        if (handleGlobalMouseMove) {
          mouseMoveHandlerRef.current = handleGlobalMouseMove;
          document.addEventListener('mousemove', mouseMoveHandlerRef.current);
        }
        
        // Prevent the "not allowed" cursor by allowing the drag
        // Set dataTransfer effectAllowed to allow copy/move
        if (params.event && params.event.dataTransfer) {
          params.event.dataTransfer.effectAllowed = 'move';
          params.event.dataTransfer.dropEffect = 'move';
        }
        
        // Also set up HTML5 drag on the row element if available
        if (params.node && params.node.rowElement) {
          params.node.rowElement.setAttribute('draggable', 'true');
          params.node.rowElement.style.cursor = 'move';
        }
      }
    } catch (error) {
      console.error('Error in handleQueueDragStart:', error);
    }
  }, [handleGlobalMouseMove]);

  // Handle drag move from Queue table - use global mouse tracking
  const handleQueueDragMove = useCallback((params) => {
    // Global mouse move handler will handle the detection
    // This callback is kept for compatibility but global handler does the work
  }, []);

  // Handle drag end from Queue table
  const handleQueueDragEnd = useCallback((params) => {
    // Check if this was an internal reorder (node still exists in queue)
    const nodeStillExists = queueUsers.some(u => u.Id === (params?.node?.data?.Id || window._workQueueDraggedUser?.Id));
    const droppedOnAllUsers = dragOverTargetRef.current === 'all-users';
    
    // Also check final mouse position as fallback
    let finalCheckDroppedOnAllUsers = false;
    if (allUsersTableContainerRef.current) {
      const elementUnderMouse = document.elementFromPoint(
        params?.event?.clientX || 0,
        params?.event?.clientY || 0
      );
      if (elementUnderMouse && allUsersTableContainerRef.current.contains(elementUnderMouse)) {
        finalCheckDroppedOnAllUsers = true;
      }
    }
    
    const shouldMoveToAllUsers = droppedOnAllUsers || finalCheckDroppedOnAllUsers;
    
    if (nodeStillExists && !shouldMoveToAllUsers && window._workQueueDragSource === 'queue-users') {
      // Internal reorder - update priorities
      if (params && params.api) {
        const newOrder = [];
        params.api.forEachNode((node) => {
          if (node.data) {
            newOrder.push(node.data);
          }
        });
        const updatedUsers = updatePriorities(newOrder);
        setQueueUsers(updatedUsers);
        if (onQueueUsersChange) {
          onQueueUsersChange(updatedUsers);
        }
      }
    } else if (window._workQueueDraggedUser && window._workQueueDragSource === 'queue-users' && shouldMoveToAllUsers) {
      // Cross-grid drop to All Users
      const userToRemove = window._workQueueDraggedUser;
      
      // Remove queue-specific fields
      const { Priority, DateAdded, ...userWithoutQueueFields } = userToRemove;
      
      // Remove from queue
      const newQueueUsers = queueUsers.filter(u => u.Id !== userToRemove.Id);
      const updatedQueueUsers = updatePriorities(newQueueUsers);
      
      // Add back to all users
      const newAllUsers = [...allUsers, userWithoutQueueFields];
      
      setQueueUsers(updatedQueueUsers);
      setAllUsers(newAllUsers);
      
      if (onQueueUsersChange) {
        onQueueUsersChange(updatedQueueUsers);
      }
      if (onAllUsersChange) {
        onAllUsersChange(newAllUsers);
      }
    }
    
    // Reset drag over styling
    if (allUsersTableContainerRef.current) {
      allUsersTableContainerRef.current.style.backgroundColor = 'transparent';
      allUsersTableContainerRef.current.style.border = 'none';
    }
    if (queueTableContainerRef.current) {
      queueTableContainerRef.current.style.backgroundColor = 'transparent';
      queueTableContainerRef.current.style.border = 'none';
    }
    
    // Clean up
    isDraggingRef.current = false;
    if (mouseMoveHandlerRef.current) {
      document.removeEventListener('mousemove', mouseMoveHandlerRef.current);
      mouseMoveHandlerRef.current = null;
    }
    window._workQueueDraggedUser = null;
    window._workQueueDragSource = null;
    dragOverTargetRef.current = null;
  }, [queueUsers, allUsers, updatePriorities, onQueueUsersChange, onAllUsersChange]);

  // Handle internal reordering within queue (from FAWTable's rowReordering)
  const handleQueueRowOrderChange = useCallback((newOrder) => {
    if (!newOrder || !Array.isArray(newOrder) || newOrder.length === 0) {
      return;
    }
    
    try {
      const reorderedUsers = newOrder.map(id => 
        queueUsers.find(u => (u.Id || u.id) === id)
      ).filter(Boolean);
      
      if (reorderedUsers.length === 0) {
        return;
      }
      
      const updatedUsers = updatePriorities(reorderedUsers);
      setQueueUsers(updatedUsers);
      if (onQueueUsersChange) {
        onQueueUsersChange(updatedUsers);
      }
    } catch (error) {
      console.error('Error in handleQueueRowOrderChange:', error);
    }
  }, [queueUsers, updatePriorities, onQueueUsersChange]);

  // Define columns for All Users table
  const allUsersColumns = [
    {
      field: 'FamilyName',
      headerName: 'Last Name',
      width: 200,
      flex: 1
    },
    {
      field: 'GivenName',
      headerName: 'First Name',
      width: 200,
      flex: 1
    },
    {
      field: 'Username',
      headerName: 'User Name',
      width: 300,
      flex: 1
    }
  ];

  // Define columns for Queue Users table
  const queueUsersColumns = [
    {
      field: 'Priority',
      headerName: 'Priority',
      width: 100,
      flex: 0
    },
    {
      field: 'FamilyName',
      headerName: 'Last Name',
      width: 200,
      flex: 1
    },
    {
      field: 'GivenName',
      headerName: 'First Name',
      width: 150,
      flex: 1
    },
    {
      field: 'Username',
      headerName: 'User Name',
      width: 300,
      flex: 1
    },
    {
      field: 'DateAdded',
      headerName: 'Date Added',
      width: 200,
      flex: 1
    }
  ];

  return (
    <Box sx={{ display: 'flex', gap: 2, width: '100%' }}>
      {/* Users in Queue Table */}
      <Box 
        ref={queueTableContainerRef}
        sx={{ flex: 1, borderRadius: '4px', transition: 'background-color 0.2s' }}
        onDragOver={(e) => {
          e.preventDefault();
          e.stopPropagation();
          if (window._workQueueDragSource === 'all-users') {
            e.dataTransfer.dropEffect = 'move';
            dragOverTargetRef.current = 'queue-users';
            e.currentTarget.style.backgroundColor = '#e3f2fd';
            e.currentTarget.style.border = '2px dashed #1976d2';
          }
        }}
        onDragLeave={(e) => {
          e.preventDefault();
          e.stopPropagation();
          if (!e.currentTarget.contains(e.relatedTarget)) {
            e.currentTarget.style.backgroundColor = 'transparent';
            e.currentTarget.style.border = 'none';
            if (dragOverTargetRef.current === 'queue-users') {
              dragOverTargetRef.current = null;
            }
          }
        }}
        onDrop={(e) => {
          e.preventDefault();
          e.stopPropagation();
          e.currentTarget.style.backgroundColor = 'transparent';
          e.currentTarget.style.border = 'none';
          if (window._workQueueDragSource === 'all-users' && window._workQueueDraggedUser) {
            handleAllUsersDragEnd({ event: e });
          }
        }}
      >
        <FAWTable
          apiRef={queueTableApiRef}
          rows={queueUsers.map((user, index) => ({
            ...user,
            id: user.Id || `queue-${index}`
          }))}
          columns={queueUsersColumns}
          loading={isLoading}
          showSearch={true}
          searchPlaceholder={searchPlaceholder}
          showPagination={true}
          showExport={false}
          showColumns={false}
          showFilter={false}
          showRefresh={false}
          hideReset={true}
          enableRowDrag={true}
          onRowDragStart={handleQueueDragStart}
          onRowDragMove={handleQueueDragMove}
          onRowDragEnd={handleQueueDragEnd}
          onRowOrderChange={handleQueueRowOrderChange}
          noRowsMessage={noQueueMessage}
          autoHeight={true}
          gridSx={{
            '& .MuiDataGrid-root': {
              height: 'auto'
            }
          }}
        />
      </Box>

      {/* All Users Table */}
      <Box 
        ref={allUsersTableContainerRef}
        sx={{ flex: 1, borderRadius: '4px', transition: 'background-color 0.2s' }}
        onDragOver={(e) => {
          e.preventDefault();
          e.stopPropagation();
          if (window._workQueueDragSource === 'queue-users') {
            e.dataTransfer.dropEffect = 'move';
            dragOverTargetRef.current = 'all-users';
            e.currentTarget.style.backgroundColor = '#e3f2fd';
            e.currentTarget.style.border = '2px dashed #1976d2';
          }
        }}
        onDragLeave={(e) => {
          e.preventDefault();
          e.stopPropagation();
          if (!e.currentTarget.contains(e.relatedTarget)) {
            e.currentTarget.style.backgroundColor = 'transparent';
            e.currentTarget.style.border = 'none';
            if (dragOverTargetRef.current === 'all-users') {
              dragOverTargetRef.current = null;
            }
          }
        }}
        onDrop={(e) => {
          e.preventDefault();
          e.stopPropagation();
          e.currentTarget.style.backgroundColor = 'transparent';
          e.currentTarget.style.border = 'none';
          if (window._workQueueDragSource === 'queue-users' && window._workQueueDraggedUser) {
            handleQueueDragEnd({ event: e });
          }
        }}
      >
        <FAWTable
          apiRef={allUsersTableApiRef}
          rows={allUsers.map((user, index) => ({
            ...user,
            id: user.Id || `all-${index}`
          }))}
          columns={allUsersColumns}
          loading={isLoading}
          showSearch={true}
          searchPlaceholder={searchPlaceholder}
          showPagination={true}
          showExport={false}
          showColumns={false}
          showFilter={false}
          showRefresh={false}
          hideReset={true}
          enableRowDrag={true}
          onRowDragStart={handleAllUsersDragStart}
          onRowDragMove={handleAllUsersDragMove}
          onRowDragEnd={handleAllUsersDragEnd}
          noRowsMessage={noRowsMessage}
          autoHeight={true}
          gridSx={{
            '& .MuiDataGrid-root': {
              height: 'auto'
            },
            '& .MuiDataGrid-row': {
              cursor: 'grab',
              '&:active': {
                cursor: 'grabbing'
              }
            }
          }}
        />
      </Box>
    </Box>
  );
};

export default WorkQueueTables;

